python3 -c "
from datetime import date, timedelta

# Find the earliest Friday the 13th starting from 0001-01-01 (proleptic Gregorian)
d = date(1, 1, 13)  # start checking the 13th of each month
earliest = None
while d.year == 1:
    if d.weekday() == 4:  # Friday
        earliest = d
        break
    # next month's 13th
    if d.month == 12:
        break
    d = d.replace(month=d.month + 1)

if not earliest:
    # check year 2 onwards
    for y in range(2, 401):
        for m in range(1, 13):
            d = date(y, m, 13)
            if d.weekday() == 4:
                earliest = d
                break
        if earliest:
            break

# Actually redo: find the very first Friday the 13th from 0001-01-01
earliest = None
for y in range(1, 401):
    for m in range(1, 13):
        d = date(y, m, 13)
        if d.weekday() == 4:
            earliest = d
            break
    if earliest:
        break

print(f'Earliest Friday the 13th (proleptic Gregorian): {earliest}')
print(f'Day of week check: {earliest.strftime(\"%A\")}')

# Count Friday the 13ths in a full 400-year cycle (the Gregorian calendar repeats every 400 years)
count = 0
for y in range(1, 401):
    for m in range(1, 13):
        if date(y, m, 13).weekday() == 4:
            count += 1

print(f'Friday the 13ths in a 400-year cycle: {count}')
print(f'Average per year: {count/400:.4f}')
"

